prompt:
Write SystemVerilog assertions for the following counter module checking it resets to 0 and increments by 1 each cycle.

Code:
module counter #(parameter WIDTH=4)(
  input clk, rst_n,
  output reg [WIDTH-1:0] count
);
  always @(posedge clk or negedge rst_n)
    if (!rst_n) count <= '0;
    else count <= count + 1'b1;
endmodule

chosen:
module counter_assertions #(parameter WIDTH=4)(
  input clk, rst_n,
  input [WIDTH-1:0] count
);
  assert property (@(posedge clk) !rst_n |-> count == '0);
  assert property (@(posedge clk)
    disable iff (!rst_n)
    count != {WIDTH{1'b1}} |=> count == $past(count) + 1'b1);
endmodule

